class StockService {
    static let shared = StockService()
    private let session = URLSession.shared
    private let apiKey = "YOUR_API_KEY"
    private let baseURL = "https://api.example.com"
    
    private init() {}
    
    func fetchStockData(symbol: String) -> AnyPublisher<StockData, Error> {
        guard let url = URL(string: "\(baseURL)/stock/\(symbol)") else {
            return Fail(error: URLError(.badURL))
                .eraseToAnyPublisher()
        }
        
        return session.dataTaskPublisher(for: url)
            .map(\.data)
            .decode(type: StockData.self, decoder: JSONDecoder())
            .receive(on: DispatchQueue.main)
            .eraseToAnyPublisher()
    }
    
    func executeTrade(trade: Trade) -> AnyPublisher<TradeResult, Error> {
        guard let url = URL(string: "\(baseURL)/trade") else {
            return Fail(error: URLError(.badURL))
                .eraseToAnyPublisher()
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")
        
        let body = [
            "symbol": trade.symbol,
            "quantity": trade.quantity,
            "type": trade.type.rawValue,
            "price": trade.price
        ]
        
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        return session.dataTaskPublisher(for: request)
            .map(\.data)
            .decode(type: TradeResult.self, decoder: JSONDecoder())
            .receive(on: DispatchQueue.main)
            .eraseToAnyPublisher()
    }
}

struct StockData: Codable {
