    let orderId: String
    let message: String
    let executedPrice: Double
    let executedQuantity: Int
}

class PortfolioManager {
    static let shared = PortfolioManager()
    private var portfolio: [String: Int] = [:]
    private var transactions: [Transaction] = []
    
    func addStock(symbol: String, quantity: Int) {
        portfolio[symbol, default: 0] += quantity
    }
    
    func removeStock(symbol: String, quantity: Int) {
        if let current = portfolio[symbol] {
            if current >= quantity {
                portfolio[symbol] = current - quantity
                if portfolio[symbol] == 0 {
                    portfolio.removeValue(forKey: symbol)
                }
            }
        }
    }
    
    func getPortfolioValue() -> Double {
        var total = 0.0
        for (symbol, quantity) in portfolio {
            if let price = StockService.shared.getCurrentPrice(symbol: symbol) {
                total += Double(quantity) * price
            }
        }
        return total
    }
    
    func getStockQuantity(symbol: String) -> Int {
        return portfolio[symbol] ?? 0
    }
}

class Transaction {
    let symbol: String
    let quantity: Int
    let type: TradeType
    let price: Double
    let timestamp: Date
    
    init(symbol: String, quantity: Int, type: TradeType, price: Double) {
        self.symbol = symbol
        self.quantity = quantity
        self.type = type
        self.price = price
        self.timestamp = Date()
    }
}

class TradeViewController: UIViewController {
    @IBOutlet weak var symbolTextField: UITextField!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var priceLabel: UILabel!
    @IBOutlet weak var buyButton: UIButton!
    @IBOutlet weak var sellButton: UIButton!
    @IBOutlet weak var portfolioLabel: UILabel!
    
    private var currentStock: StockData?
    private var cancellables = Set<AnyCancellable>()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        setupBindings()
    }
    
    private func setupUI() {
        buyButton.backgroundColor = .systemGreen
        sellButton.backgroundColor = .systemRed
        buyButton.layer.cornerRadius = 8
        sellButton.layer.cornerRadius = 8
    }
    
    private func setupBindings() {
        symbolTextField.addTarget(self, action: #selector(symbolChanged), for: .editingChanged)
        quantityTextField.addTarget(self, action: #selector(quantityChanged), for: .editingChanged)
    }
    
    @objc private func symbolChanged() {
        guard let symbol = symbolTextField.text, !symbol.isEmpty else { return }
        fetchStockData(symbol: symbol)
    }
    
    @objc private func quantityChanged() {
        updatePriceLabel()
    }
    
    private func fetchStockData(symbol: String) {
        StockService.shared.fetchStockData(symbol: symbol)
            .sink(
                receiveCompletion: { completion in
                    if case .failure(let error) = completion {
                        print("Error fetching stock data: \(error)")
                    }
                },
                receiveValue: { [weak self] stock in
                    self?.currentStock = stock
                    self?.updatePriceLabel()
                }
            )
            .store(in: &cancellables)
    }
    
    private func updatePriceLabel() {
        guard let stock = currentStock,
              let quantity = Int(quantityTextField.text ?? "0") else {
            priceLabel.text = "Price: $0.00"
            return
        }
        
        let total = stock.price * Double(quantity)
        priceLabel.text = String(format: "Total: $%.2f", total)
    }
    
    @IBAction func buyTapped(_ sender: UIButton) {
        executeTrade(type: .buy)
    }
    
    @IBAction func sellTapped(_ sender: UIButton) {
        executeTrade(type: .sell)
    }
    
    private func executeTrade(type: TradeType) {
        guard let symbol = symbolTextField.text,
              let quantity = Int(quantityTextField.text ?? "0"),
              let price = currentStock?.price else { return }
        
        let trade = Trade(symbol: symbol, quantity: quantity, type: type, price: price)
        
        StockService.shared.executeTrade(trade: trade)
            .sink(
                receiveCompletion: { completion in
                    if case .failure(let error) = completion {
                        print("Trade execution failed: \(error)")
                    }
                },
                receiveValue: { result in
                    if result.success {
                        self.updatePortfolio(symbol: symbol, quantity: quantity, type: type)
                        self.showSuccess(message: "Trade executed successfully!")
                    } else {
                        self.showError(message: result.message)
                    }
                }
            )
            .store(in: &cancellables)
    }
    
    private func updatePortfolio(symbol: String, quantity: Int, type: TradeType) {
        if type == .buy {
            PortfolioManager.shared.addStock(symbol: symbol, quantity: quantity)
        } else {
            PortfolioManager.shared.removeStock(symbol: symbol, quantity: quantity)
        }
        updatePortfolioLabel()
    }
    
    private func updatePortfolioLabel() {
        let portfolioValue = PortfolioManager.shared.getPortfolioValue()
        portfolioLabel.text = String(format: "Portfolio: $%.2f", portfolioValue)
    }
    
    private func showSuccess(message: String) {
        let alert = UIAlertController(title: "Success", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func showError(message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

