class StockListViewController: UIViewController {
    @IBOutlet weak var tableView: UITableView!
    
    private var stocks: [StockData] = []
    private var cancellables = Set<AnyCancellable>()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupTableView()
        loadStocks()
    }
    
    private func setupTableView() {
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "StockCell")
    }
    
    private func loadStocks() {
        let symbols = ["AAPL", "GOOGL", "MSFT", "AMZN", "TSLA"]
        
        Publishers.MergeMany(
            symbols.map { symbol in
                StockService.shared.fetchStockData(symbol: symbol)
            }
        )
        .collect()
        .sink(
            receiveCompletion: { completion in
                if case .failure(let error) = completion {
                    print("Error loading stocks: \(error)")
                }
            },
            receiveValue: { [weak self] stocks in
                self?.stocks = stocks
                self?.tableView.reloadData()
            }
        )
        .store(in: &cancellables)
    }
}

extension StockListViewController: UITableViewDataSource, UITableViewDelegate {
